<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Mini Spreadsheet</title>
    <style>
        * {
            box-sizing: border-box;
            margin: 0;
            padding: 0;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
        }
        body {
            display: flex;
            justify-content: center;
            align-items: center;
            min-height: 100vh;
            background: #f0f2f5;
            flex-direction: column;
            gap: 20px;
            padding: 20px;
        }
        .app-container {
            background: white;
            border-radius: 12px;
            box-shadow: 0 4px 20px rgba(0,0,0,0.1);
            padding: 24px;
            display: flex;
            flex-direction: column;
            align-items: center;
            min-width: 600px;
            min-height: 400px;
        }
        .grid {
            display: grid;
            grid-template-columns: 50px repeat(10, 80px);
            grid-template-rows: 30px repeat(10, 35px);
            gap: 2px;
            background: #e1e4e8;
            border: 1px solid #d0d5dd;
            border-radius: 8px;
            overflow: hidden;
            margin-bottom: 20px;
        }
        .header {
            background: #f7f8fa;
            display: flex;
            align-items: center;
            justify-content: center;
            font-weight: 600;
            color: #344054;
            font-size: 14px;
            border-bottom: 1px solid #d0d5dd;
            border-right: 1px solid #d0d5dd;
        }
        .corner {
            background: #f7f8fa;
        }
        .row-header {
            background: #f7f8fa;
            display: flex;
            align-items: center;
            justify-content: center;
            font-weight: 600;
            color: #344054;
            font-size: 14px;
            border-right: 1px solid #d0d5dd;
        }
        .cell {
            background: white;
            border: 1px solid #e1e4e8;
            display: flex;
            align-items: center;
            justify-content: center;
            transition: background 0.1s;
        }
        .cell input {
            width: 100%;
            height: 100%;
            border: none;
            text-align: center;
            font-size: 14px;
            padding: 4px;
            outline: none;
            background: transparent;
            color: #1a1a1a;
        }
        .cell input:focus {
